        int[][] edges = { new[] {0,1}, new[] {0,2}, new[] {1,3}, new[] {2,3} };
        foreach (var edge in edges)
        {
            if (!graph.ContainsKey(edge[0])) graph[edge[0]] = new List<int>();
            if (!graph.ContainsKey(edge[1])) graph[edge[1]] = new List<int>();
            graph[edge[0]].Add(edge[1]);
            graph[edge[1]].Add(edge[0]);
        }

        foreach (var (node, neighbors) in graph)
            Console.WriteLine($"{node}: [{String.Join(", ", neighbors)}]");
    }
}

